window.WIREFRAME_SCREENS = Object.freeze([
  {
    id: "ob1",
    html: "    <!-- ============ 1.1 WELCOME ============ -->\n    <section class=\"screen active\" id=\"ob1\">\n      <div class=\"shead\"><h2>Onboarding · Welcome</h2><span class=\"route\">step 1 / 4</span></div>\n      <p class=\"sdesc\">Sets expectations and states the trust promise in one line. One primary action, one recovery path.</p>\n      <div class=\"frame\">\n        <div class=\"tbar\"><div class=\"dots\"><i></i><i></i><i></i></div><span class=\"ttl\">Locality Setup</span>\n          <div class=\"steps\"><i class=\"on\"></i><i></i><i></i><i></i></div></div>\n        <div style=\"padding:60px 40px;text-align:center\">\n          <img class=\"welcome-logo\" src=\"assets/locality-logo-dark.svg\" alt=\"Locality\">\n          <div style=\"font-size:20px;font-weight:600;letter-spacing:-.02em;max-width:420px;margin:0 auto\">\n            Turn your Notion and other docs into local files your AI agents can edit — safely.</div>\n          <p style=\"color:var(--muted);max-width:400px;margin:12px auto 26px\">\n            Your edits stay on your machine until you review them in Review Center and push them back.</p>\n          <span class=\"btn btn-primary\" data-go=\"ob2\">Get started →</span>\n          <div style=\"margin-top:16px\"><span class=\"linkish\" data-go=\"home\">Restore from an existing mount</span></div>\n        </div>\n      </div>\n      <div class=\"notes\"><b>notes</b> — traffic-light chrome + 4-dot setup indicator persists across required setup steps ·\n      \"safely\" is the thesis word: repeated in review-mode copy · secondary link handles reinstall/repair users.</div>\n    </section>"
  },
  {
    id: "ob2",
    html: "    <!-- ============ 1.2 CONNECT ============ -->\n    <section class=\"screen\" id=\"ob2\">\n      <div class=\"shead\"><h2>Onboarding · Connect a source</h2><span class=\"route\">step 2 / 4</span></div>\n      <p class=\"sdesc\">First meaningful setup action. Connector cards scale as new sources ship, while OAuth waits and errors stay inline.</p>\n      <div class=\"frame\">\n        <div class=\"tbar\"><div class=\"dots\"><i></i><i></i><i></i></div><span class=\"ttl\">Locality Setup</span>\n          <div class=\"steps\"><i class=\"on\"></i><i class=\"on\"></i><i></i><i></i></div></div>\n        <div style=\"padding:28px 36px 32px\">\n          <div style=\"font-size:17px;font-weight:600\">Connect a source</div>\n          <p style=\"color:var(--muted);margin:4px 0 18px\">Locality only reads and writes the pages you authorize.</p>\n          <div style=\"display:grid;grid-template-columns:1fr 1fr;gap:12px;max-width:560px\">\n            <div class=\"card\" style=\"padding:14px\">\n              <div style=\"display:flex;gap:8px;align-items:center;font-weight:600\"><span class=\"src src-n\">N</span>Notion</div>\n              <p style=\"color:var(--muted);font-size:11.5px;margin:6px 0 12px\">Workspaces, pages, databases</p>\n              <span class=\"btn btn-primary btn-sm\" data-go=\"ob3\">Connect</span>\n            </div>\n            <div class=\"card\" style=\"padding:14px;opacity:.55\">\n              <div style=\"display:flex;gap:8px;align-items:center;font-weight:600\"><span class=\"src src-g\">G</span>Google Docs</div>\n              <p style=\"color:var(--muted);font-size:11.5px;margin:6px 0 12px\">Coming soon</p>\n              <span class=\"btn btn-sm\" aria-disabled=\"true\">Connect</span>\n            </div>\n          </div>\n          <div style=\"display:flex;gap:8px;align-items:center;margin-top:18px;color:var(--muted);font-size:12px\">\n            <span class=\"chip c-review\">⟳ waiting</span> Waiting for authorization in your browser…\n            <span class=\"btn btn-sm\" data-go=\"ob2\">Reopen browser</span><span class=\"linkish\">Copy sign-in link</span>\n          </div>\n          <div style=\"display:flex;justify-content:flex-end;gap:8px;margin-top:26px\">\n            <span class=\"btn\" data-go=\"ob1\">Back</span><span class=\"btn btn-primary\" style=\"opacity:.5\" data-go=\"ob3\">Continue →</span>\n          </div>\n        </div>\n      </div>\n      <div class=\"notes\"><b>states</b> — error: “We couldn’t connect. [Try again]” · success: card shows workspace\n      avatar + name + Synced-teal “Connected ✓”, Continue enables · copy-link is the no-browser fallback ·\n      product education moved to optional step 1.5 so setup starts with action.</div>\n    </section>"
  },
  {
    id: "ob3",
    html: "    <!-- ============ 1.3 FOLDER ============ -->\n    <section class=\"screen\" id=\"ob3\">\n      <div class=\"shead\"><h2>Onboarding · Local folder</h2><span class=\"route\">step 3 / 4</span></div>\n      <p class=\"sdesc\">Show where files appear and keep setup progress, approval waits, and recovery actions on this screen only.</p>\n      <div class=\"frame\">\n        <div class=\"tbar\"><div class=\"dots\"><i></i><i></i><i></i></div><span class=\"ttl\">Locality Setup</span>\n          <div class=\"steps\"><i class=\"on\"></i><i class=\"on\"></i><i class=\"on\"></i><i></i></div></div>\n        <div style=\"padding:26px 36px 30px;max-width:620px\">\n          <div style=\"font-size:17px;font-weight:600;margin-bottom:14px\">Create your local folder</div>\n          <div style=\"font-size:12px;color:var(--muted);margin-bottom:6px\">Your connected source will appear here:</div>\n          <div class=\"pathchip\"><span>~/Library/CloudStorage/Locality/notion</span><em>Copy</em></div>\n          <div style=\"margin:6px 0 18px\"><span class=\"linkish\">Choose a different location…</span></div>\n\n          <div class=\"h-min\">Verifying setup</div>\n          <div class=\"card\">\n            <div class=\"rowline\"><span class=\"chip c-synced\">✓</span><span class=\"grow\">Folder created</span></div>\n            <div class=\"rowline\"><span class=\"chip c-synced\">✓</span><span class=\"grow\">File Provider registered</span></div>\n            <div class=\"rowline\"><span class=\"chip c-review\">⟳</span><span class=\"grow\">Waiting for test file to appear…</span></div>\n          </div>\n          <div style=\"display:flex;justify-content:flex-end;gap:8px;margin-top:22px\">\n            <span class=\"btn\" data-go=\"ob2\">Back</span><span class=\"btn btn-primary\" data-go=\"ob4\">Continue →</span>\n          </div>\n          <div style=\"font-size:11px;color:var(--faint);margin-top:10px\">Use this step for approval-required, waiting-for-folder, and retry-needed states.</div>\n        </div>\n      </div>\n      <div class=\"notes\"><b>error state</b> — a failed check swaps to ✕ Error red with a fix action:\n      “File Provider not approved → [Open System Settings]” · keep all setup and recovery states on this screen.</div>\n    </section>"
  },
  {
    id: "ob4",
    html: "    <!-- ============ 1.4 READY ============ -->\n    <section class=\"screen\" id=\"ob4\">\n      <div class=\"shead\"><h2>Onboarding · Ready</h2><span class=\"route\">step 4 / 4</span></div>\n      <p class=\"sdesc\">Completion handoff: mounted path, optional agent guidance, and next action into the product.</p>\n      <div class=\"frame\">\n        <div class=\"tbar\"><div class=\"dots\"><i></i><i></i><i></i></div><span class=\"ttl\">Locality Setup</span>\n          <div class=\"steps\"><i class=\"on\"></i><i class=\"on\"></i><i class=\"on\"></i><i class=\"on\"></i></div></div>\n        <div style=\"padding:28px 36px 30px;max-width:620px\">\n          <div style=\"display:flex;align-items:center;gap:8px;font-size:17px;font-weight:600;margin-bottom:16px\">\n            <span class=\"chip c-synced\" style=\"font-size:13px\">✓</span> Locality is ready</div>\n          <div style=\"font-size:12px;color:var(--muted);margin-bottom:6px\">Your local workspace is mounted here:</div>\n          <div class=\"pathchip\"><span>~/Library/CloudStorage/Locality/notion</span><em>Copy</em></div>\n          <div style=\"font-size:11.5px;color:var(--muted);margin:6px 0 16px\">Agents can open this folder now, and Locality will hold their edits for review unless Live Mode is enabled for this source.</div>\n          <div class=\"card\" style=\"padding:12px 14px\">\n            <div style=\"font-weight:600;font-size:12.5px\">Agent guidance is optional</div>\n            <div style=\"font-size:11.5px;color:var(--muted);margin:4px 0 10px\">\n              Open Locality now, or learn how AGENTS.md and editor guidance help agents use the mount correctly.</div>\n            <span class=\"btn btn-sm\" data-go=\"ob5\">View optional guide</span>\n          </div>\n          <div style=\"display:flex;justify-content:flex-end;gap:8px;margin-top:20px\">\n            <span class=\"btn\" data-go=\"files\">Open my folder</span><span class=\"btn btn-primary\" data-go=\"home\">Open Locality →</span>\n          </div>\n        </div>\n      </div>\n      <div class=\"notes\"><b>handoff</b> — required onboarding ends here ·\n      optional education sits behind a secondary action so the setup path stays short.</div>\n    </section>"
  },
  {
    id: "ob5",
    html: "    <!-- ============ 1.5 OPTIONAL AGENT GUIDE ============ -->\n    <section class=\"screen\" id=\"ob5\">\n      <div class=\"shead\"><h2>Onboarding · Optional agent guide</h2><span class=\"route\">optional after setup</span></div>\n      <p class=\"sdesc\">Product knowledge appears after the user has completed setup. This screen explains the filesystem-first model without blocking connection.</p>\n      <div class=\"frame\">\n        <div class=\"tbar\"><div class=\"dots\"><i></i><i></i><i></i></div><span class=\"ttl\">Locality Setup · Optional</span>\n          <div class=\"steps\"><i class=\"on\"></i><i class=\"on\"></i><i class=\"on\"></i><i class=\"on\"></i></div></div>\n        <div style=\"padding:28px 36px 32px\">\n          <div style=\"font-size:17px;font-weight:600\">Agents work in files you can see</div>\n          <p style=\"color:var(--muted);margin:4px 0 18px\">Each connected source appears as a local folder. Locality adds guidance files like AGENTS.md and CLAUDE.md so agents follow the filesystem contract, and edits stay local until review or Live Mode safely syncs them.</p>\n          <div style=\"display:grid;grid-template-columns:1.05fr .95fr;gap:14px;max-width:620px\">\n            <div class=\"card\" style=\"padding:14px\">\n              <div class=\"card-h\">Visible local workspace</div>\n              <div class=\"rowline\"><span class=\"grow\">notion-main/AGENTS.md</span><span class=\"chip c-synced\">Guide</span></div>\n              <div class=\"rowline\"><span class=\"grow\">Roadmap/page.md</span><span class=\"chip c-review\">Edited</span></div>\n              <div class=\"rowline\"><span class=\"grow\">Launch Plan/page.md</span><span class=\"chip c-synced\">Synced</span></div>\n            </div>\n            <div class=\"card\" style=\"padding:14px\">\n              <div style=\"font-weight:600;font-size:12.5px;margin-bottom:8px\">What Locality does</div>\n              <div class=\"check on\"><i>✓</i><div><b style=\"font-size:12px\">Keeps files visible</b><small>Agents and humans work in the same folder.</small></div></div>\n              <div class=\"check on\"><i>✓</i><div><b style=\"font-size:12px\">Writes guidance</b><small>Agents see the filesystem contract inside the mount.</small></div></div>\n              <div class=\"check on\"><i>✓</i><div><b style=\"font-size:12px\">Keeps review explicit</b><small>Review Center handles approvals and exceptions.</small></div></div>\n            </div>\n          </div>\n          <div style=\"display:flex;justify-content:flex-end;gap:8px;margin-top:26px\">\n            <span class=\"btn\" data-go=\"ob4\">Back</span><span class=\"btn\" data-go=\"agents\">Configure agent guidance</span><span class=\"btn btn-primary\" data-go=\"home\">Open Locality →</span>\n          </div>\n        </div>\n      </div>\n      <div class=\"notes\"><b>goal</b> — optional education after setup avoids slowing the first-run path ·\n      users can skip it, while teams can still use it during demos and onboarding reviews.</div>\n    </section>"
  },
  {
    id: "home",
    html: "    <!-- ============ 2.1 HOME ============ -->\n    <section class=\"screen\" id=\"home\">\n      <div class=\"shead\"><h2>Home</h2><span class=\"route\">/</span></div>\n      <p class=\"sdesc\">Glanceable health, quick locate, recent work, and a clear path into Review Center when agent edits need approval.</p>\n      <div class=\"frame\" data-app-shell=\"home\" data-app-title=\"Home\" data-strip-legacy-sidebar=\"true\">\n        <div class=\"tbar\"><div class=\"dots\"><i></i><i></i><i></i></div><span class=\"ttl\">Locality</span></div>\n        <div class=\"appshell\">\n          <div class=\"snav\">\n            <div class=\"logo\"><span class=\"aperture\"></span>Locality</div>\n            <a class=\"on\" href=\"#\">⌂ Home</a>\n            <a href=\"#\">◫ Sources</a>\n            <a href=\"#\">● Review Center <span class=\"cnt\">4</span></a>\n            <a href=\"#\">⚙ Settings</a>\n            <div class=\"foot\"><span class=\"chip c-synced\">✓</span> Synced · 2m ago</div>\n          </div>\n          <div>\n            <div class=\"statusbar\"><span class=\"chip c-synced\">✓ All changes reviewed</span>\n              <span class=\"sp\">Live mode: Off <span class=\"toggle\"></span></span></div>\n            <div class=\"content\">\n              <div class=\"statgrid\">\n                <div class=\"stat\" data-go=\"sources\"><div class=\"lbl\">Sources</div><div class=\"num\">2</div></div>\n                <div class=\"stat\" data-go=\"reviewcenter\"><div class=\"lbl\">Awaiting review</div><div class=\"num\" style=\"color:var(--amber)\">4</div></div>\n                <div class=\"stat\" data-go=\"problems\"><div class=\"lbl\">Problems</div><div class=\"num\" style=\"color:var(--teal)\">0 ✓</div></div>\n              </div>\n              <div class=\"h-min\">Locate a page</div>\n              <div class=\"wf-input\" data-go=\"locate\">🔎 Paste a Notion URL or type a title…</div>\n              <div class=\"h-min\">Recent files</div>\n              <div class=\"card\">\n                <div class=\"rowline\" data-go=\"reviewcenter\"><span class=\"src src-n\">N</span><span class=\"grow\">Roadmap.md</span>\n                  <span class=\"chip c-review-needed\">● Needs review</span><span class=\"meta\">2m ago</span></div>\n                <div class=\"rowline\" data-go=\"files\"><span class=\"src src-n\">N</span><span class=\"grow\">Specs/Auth.md</span>\n                  <span class=\"chip c-synced\">✓ Synced</span><span class=\"meta\">1h ago</span></div>\n                <div class=\"rowline\" data-go=\"files\"><span class=\"src src-n\">N</span><span class=\"grow\">Notes/Standup.md</span>\n                  <span class=\"chip c-draft\">◐ Draft</span><span class=\"meta\">3h ago</span></div>\n              </div>\n            </div>\n          </div>\n        </div>\n      </div>\n      <div class=\"notes\"><b>sidebar rule</b> — primary nav stays to Home, Sources, Review Center, Settings; Files, Activity,\n      and Problems surface contextually from those places · <b>empty state</b> — no sources: stat cards replaced by one panel\n      “Connect your first source [Connect Notion]” · <b>keyboard</b> — “/” focuses Locate, Cmd+1..4 jumps sidebar.</div>\n    </section>"
  },
  {
    id: "files",
    html: "    <!-- ============ 2.1.1 FILES BROWSER ============ -->\n    <section class=\"screen\" id=\"files\">\n      <div class=\"shead\"><h2>Files — unified browser</h2><span class=\"route\">/files</span></div>\n      <p class=\"sdesc\">A searchable file browser reached from Home search, recent files, source detail, Review Center file actions, or tray search. It is a subpage, not a primary sidebar item.</p>\n      <div class=\"frame\" data-app-shell=\"home\" data-app-title=\"Files browser\" data-app-kind=\"subpage\"\n        data-app-crumbs=\"Home|Files browser\"\n        data-app-entry=\"Home search, Recent file row, Source detail > Open folder, Review Center > Open file, tray search\">\n        <div class=\"tbar\"><div class=\"dots\"><i></i><i></i><i></i></div><span class=\"ttl\">Locality — Files</span></div>\n        <div class=\"appshell\" style=\"grid-template-columns:150px 1fr\">\n          <div class=\"snav\">\n            <div class=\"sect-label\">Sources</div>\n            <a href=\"#\">○ All</a><a class=\"on\" href=\"#\">● Notion</a>\n            <a href=\"#\" style=\"opacity:.5\">○ Google Docs <span class=\"meta\" style=\"font-size:9px\">soon</span></a>\n            <div class=\"sect-label\">Filters</div>\n            <a href=\"#\">Needs review</a><a href=\"#\">Conflicts</a><a href=\"#\">Synced</a>\n          </div>\n          <div>\n            <div class=\"statusbar\"><b style=\"font-size:13px\">Files</b>\n              <span class=\"sp\"><span class=\"wf-input\" style=\"padding:3px 8px\">🔎 search</span>\n              <span class=\"btn btn-sm\">Status: All ▾</span></span></div>\n            <div class=\"content\">\n              <div class=\"card\">\n                <div class=\"rowline\" style=\"color:var(--faint);font-size:10.5px;text-transform:uppercase;letter-spacing:.06em\">\n                  <span class=\"grow\">Name</span><span style=\"width:52px\">Source</span><span style=\"width:86px\">Status</span><span style=\"width:60px\">Modified</span></div>\n                <div class=\"rowline\"><span class=\"grow\">📁 Specs/</span><span style=\"width:52px\"><span class=\"src src-n\">N</span></span>\n                  <span style=\"width:86px;color:var(--faint)\">—</span><span style=\"width:60px\" class=\"meta\">—</span></div>\n                <div class=\"rowline\"><span class=\"grow\">📄 Roadmap.md</span><span style=\"width:52px\"><span class=\"src src-n\">N</span></span>\n                  <span style=\"width:86px\"><span class=\"chip c-review-needed\">● Review</span></span><span style=\"width:60px\" class=\"meta\">2m</span></div>\n                <div class=\"rowline\" style=\"background:var(--teal-wash)\"><span class=\"grow\">📄 Auth.md</span><span style=\"width:52px\"><span class=\"src src-n\">N</span></span>\n                  <span style=\"width:86px\"><span class=\"chip c-synced\">✓ Synced</span></span><span style=\"width:60px\" class=\"meta\">1h</span></div>\n                <div class=\"rowline\"><span class=\"grow\">📄 Standup.md</span><span style=\"width:52px\"><span class=\"src src-n\">N</span></span>\n                  <span style=\"width:86px\"><span class=\"chip c-draft\">◐ Draft</span></span><span style=\"width:60px\" class=\"meta\">3h</span></div>\n                <div class=\"rowline\"><span class=\"grow\">📄 Old.md</span><span style=\"width:52px\"><span class=\"src src-n\">N</span></span>\n                  <span style=\"width:86px\"><span class=\"chip c-conflict\">⚠ Conflict</span></span><span style=\"width:60px\" class=\"meta\">5h</span></div>\n              </div>\n              <div class=\"pathchip\" style=\"margin-top:12px\">\n                <span>~/Library/CloudStorage/Locality/notion/Specs/Auth.md</span><em>Reveal · Copy</em></div>\n            </div>\n          </div>\n        </div>\n      </div>\n      <div class=\"notes\"><b>row menu</b> — Open · Reveal in Finder · Locate original · Diff (if awaiting review) · Set sync mode ·\n      <b>selection</b> — highlighted row drives the footer path; arrows move, Enter opens.</div>\n    </section>"
  },
  {
    id: "sources",
    html: "    <!-- ============ 2.2 SOURCES ============ -->\n    <section class=\"screen\" id=\"sources\">\n      <div class=\"shead\"><h2>Sources</h2><span class=\"route\">/sources · /sources/:id</span></div>\n      <p class=\"sdesc\">Connected workspaces, mount health, and per-source sync controls in one place. Daily write decisions still route through Review Center when review is required.</p>\n      <div class=\"frame\" data-app-shell=\"sources\" data-app-title=\"Sources\">\n        <div class=\"tbar\"><div class=\"dots\"><i></i><i></i><i></i></div><span class=\"ttl\">Locality — Sources</span></div>\n        <div class=\"content\" style=\"padding:18px 22px\">\n          <div style=\"display:flex;align-items:center;margin-bottom:14px\"><b style=\"font-size:14px\">Sources</b>\n            <span class=\"btn btn-primary btn-sm\" style=\"margin-left:auto\" data-go=\"ob2\">+ Add source</span></div>\n          <div class=\"card\" style=\"margin-bottom:12px;padding:14px\">\n            <div style=\"display:flex;align-items:center;gap:8px;font-weight:600\">\n              <span class=\"src src-n\">N</span>Notion — Acme Team\n              <span class=\"chip c-synced\" style=\"margin-left:auto\">✓ Healthy</span></div>\n            <div class=\"pathchip\" style=\"margin:10px 0\"><span>~/Library/CloudStorage/Locality/notion</span><em>Copy</em></div>\n            <div class=\"source-sync\" style=\"margin-bottom:12px\">\n              <b>Sync for this source</b><span class=\"btn btn-sm\">Review mode ▾</span><span class=\"chip c-paused\">Live off</span>\n              <span>412 pages · 3 databases</span></div>\n            <div style=\"display:flex;gap:8px;flex-wrap:wrap\">\n              <span class=\"btn btn-sm\" data-go=\"files\">Open folder</span><span class=\"btn btn-sm\">Sync now</span><span class=\"btn btn-sm\">Pause source ▾</span>\n              <span class=\"btn btn-sm\" data-go=\"srcdetail\">Reconnect</span><span class=\"btn btn-ghost btn-sm\" data-go=\"srcdetail\">Details →</span></div>\n          </div>\n          <div class=\"card\" style=\"padding:14px;opacity:.6\">\n            <div style=\"display:flex;align-items:center;gap:8px;font-weight:600\">\n              <span class=\"src src-g\">G</span>Google Docs<span class=\"chip c-draft\" style=\"margin-left:auto\">Coming soon</span></div>\n            <p style=\"font-size:11.5px;color:var(--muted);margin:6px 0 10px\">Connect a Google account to mount Docs as local Markdown.</p>\n            <span class=\"btn btn-sm\">Notify me</span>\n          </div>\n        </div>\n      </div>\n      <div class=\"notes\"><b>sync model</b> — Settings defines the default for new sources; each source card has its own mode,\n      Sync now, and Pause source controls · source detail adds diagnostics, scoped access, and the hidden danger-zone accordion.</div>\n    </section>"
  },
  {
    id: "reviewcenter",
    html: "    <!-- ============ 2.3 REVIEW CENTER ============ -->\n    <section class=\"screen\" id=\"reviewcenter\">\n      <div class=\"shead\"><h2>Review Center — Live Mode on</h2><span class=\"route\">/review</span></div>\n      <p class=\"sdesc\">When Live Mode is on, safe edits auto-sync and appear in Activity. Review Center becomes the exception queue for approvals, conflicts, policy pauses, and failed syncs.</p>\n      <div class=\"frame\" data-app-shell=\"review\" data-app-title=\"Review Center\">\n        <div class=\"tbar\"><div class=\"dots\"><i></i><i></i><i></i></div><span class=\"ttl\">Locality — Review Center</span></div>\n        <div class=\"appshell\" style=\"grid-template-columns:224px 1fr\">\n          <div class=\"snav\" style=\"padding:0\">\n            <div style=\"padding:10px 12px;border-bottom:1px solid var(--line-soft)\">\n              <div style=\"font-size:12.5px;font-weight:600\">4 items need attention</div>\n              <div style=\"font-size:11px;color:var(--muted);margin-top:2px\">Live Mode on · safe edits sync automatically</div>\n            </div>\n            <div style=\"display:flex;gap:4px;padding:8px 10px;border-bottom:1px solid var(--line-soft)\">\n              <span class=\"btn btn-sm btn-primary\">All</span>\n              <span class=\"btn btn-sm\">Approvals</span>\n              <span class=\"btn btn-sm\">Problems</span>\n            </div>\n            <div class=\"sect-label\">Needs manual approval</div>\n            <div class=\"rowline\"><span class=\"check on\"><i>✓</i></span><span class=\"src src-n\">N</span>\n              <span class=\"grow\">Roadmap.md</span><span class=\"chip c-review-needed\">Rule</span></div>\n            <div class=\"rowline\" style=\"background:var(--teal-wash)\"><span class=\"check on\"><i>✓</i></span><span class=\"src src-n\">N</span>\n              <span class=\"grow\">Auth.md</span><span class=\"chip c-review-needed\">Policy</span></div>\n            <div class=\"sect-label\">Paused by safety</div>\n            <div class=\"rowline\"><span class=\"check on\"><i>✓</i></span><span class=\"src src-n\">N</span>\n              <span class=\"grow\">Old.md</span><span class=\"chip c-conflict\">Delete</span></div>\n            <div class=\"rowline\"><span class=\"check\"><i></i></span><span class=\"src src-n\">N</span>\n              <span class=\"grow\">Notes.md</span><span class=\"chip c-conflict\">Conflict</span></div>\n            <div style=\"margin-top:auto;border-top:1px solid var(--line-soft);padding:10px 12px\">\n              <div style=\"font-size:11px;color:var(--muted);margin-bottom:8px\">3 selected · Live Mode stays paused for selected files</div>\n              <div style=\"display:flex;gap:6px\">\n                <span class=\"btn btn-sm\" style=\"flex:1;justify-content:center\">Reject</span>\n                <span class=\"btn btn-primary btn-sm\" style=\"flex:1;justify-content:center\">Approve</span>\n              </div>\n            </div>\n          </div>\n          <div>\n            <div class=\"statusbar\"><b style=\"font-size:13px\">Auth.md</b>\n              <span class=\"meta\">Cursor · Live Mode paused for this file · +1 -1</span>\n              <span class=\"sp\"><span class=\"btn btn-sm\" data-go=\"files\">Open file</span><span class=\"btn btn-sm\" data-go=\"agents\">Rule…</span></span></div>\n          <div class=\"content\">\n            <div class=\"card\" style=\"padding:10px 12px;margin-bottom:12px;background:var(--amber-wash);border-color:rgba(192,138,0,.2)\">\n              <div style=\"font-weight:600;font-size:12px;color:var(--amber)\">Review required by source policy</div>\n              <div style=\"font-size:11.5px;color:var(--muted);margin-top:3px\">Safe edits from this source can live-sync, but this file matches a rule that requires human approval before push.</div>\n            </div>\n            <div class=\"diff\">\n              <div class=\"dh\">Auth.md\n                <div class=\"seg\"><span class=\"on\">Unified</span><span>Split</span></div></div>\n              <div class=\"dl dl-ctx\">  ## Overview</div>\n              <div class=\"dl dl-del\">- Old sentence about auth.</div>\n              <div class=\"dl dl-add\">+ New sentence written by the agent.</div>\n              <div class=\"dl dl-ctx\">  Unchanged context line…</div>\n            </div>\n            <div style=\"display:flex;gap:6px;flex-wrap:wrap;margin-top:12px\">\n              <span class=\"btn btn-sm\">Reject selected</span><span class=\"btn btn-primary btn-sm\" data-go=\"review\">Approve &amp; push</span>\n              <span class=\"btn btn-sm\">Pull latest</span><span class=\"btn btn-sm\">Reset to remote</span>\n              <span class=\"btn btn-sm\" data-go=\"conflict\">Resolve conflict</span></div>\n            <div style=\"margin-top:14px;font-size:12px;color:var(--muted)\">\n              Auto-synced work skips this queue and appears in Activity. Revert is shown only when a journal-backed reverse plan is still safe.</div>\n          </div>\n          </div>\n        </div>\n      </div>\n      <div class=\"notes\"><b>Live Mode flow</b> — clean remote pulls and safe local pushes do not stop here; they go straight to Activity.\n      Review Center shows destructive changes, same-block conflicts, remote drift, large plans, permission failures, and source rules requiring approval ·\n      <b>empty state</b> — “No review needed. Live Mode synced safe changes automatically.”</div>\n    </section>"
  },
  {
    id: "review",
    html: "    <!-- ============ 2.3.1 PUSH APPROVAL ============ -->\n    <section class=\"screen\" id=\"review\">\n      <div class=\"shead\"><h2>Push approval — final gate</h2><span class=\"route\">/review/push (modal route)</span></div>\n      <p class=\"sdesc\">A modal over Review Center: Back/Esc pushes nothing and preserves selection. Deletions gate the push button behind an explicit checkbox.</p>\n      <div class=\"frame overlayed\" data-app-shell=\"review\" data-app-title=\"Push approval\" data-app-kind=\"modal\"\n        data-app-crumbs=\"Review Center|Push approval\"\n        data-app-entry=\"Review Center > Approve selected, Review Center > approve file row\">\n        <div class=\"tbar\"><div class=\"dots\"><i></i><i></i><i></i></div><span class=\"ttl\">Locality — Review Center</span></div>\n        <div class=\"under\" style=\"height:360px;background:var(--wash)\"></div>\n        <div class=\"modal\">\n          <div class=\"mcard\" role=\"dialog\" aria-label=\"Approve and push\">\n            <h3>Approve and push</h3>\n            <p style=\"font-size:12px;color:var(--muted)\">You’re about to push <b>3 changes</b> to Notion\n              <span class=\"src src-n\" style=\"vertical-align:-3px\">N</span></p>\n            <div class=\"plan\">\n              <div class=\"pr\">▸ Pages updated <span class=\"n\">2</span></div>\n              <div class=\"pr\">▸ Database rows updated <span class=\"n\">1</span></div>\n              <div class=\"pr\" style=\"color:var(--red)\">▾ Pages deleted <span class=\"n\">1 ⚠</span></div>\n              <div class=\"subrow\">• Old.md → “Old Project Notes”</div>\n            </div>\n            <div class=\"warnbox\">⚠ This will permanently delete 1 page in Notion.</div>\n            <div class=\"check\"><i></i><span>I understand 1 page will be deleted.</span></div>\n            <div class=\"mfoot\"><span class=\"btn\">Back</span>\n              <span class=\"btn btn-danger\" aria-disabled=\"true\" disabled>Push 3 changes</span></div>\n          </div>\n        </div>\n      </div>\n      <div class=\"notes\"><b>states</b> — pushing: progress bar “Pushing 2 of 3…” · success toast + Activity entry ·\n      partial failure routes to Sync Problems · <b>focus</b> — lands on Back, Esc = Back, never pushes.</div>\n    </section>"
  },
  {
    id: "problems",
    html: "    <!-- ============ 2.3.3 SYNC PROBLEMS ============ -->\n    <section class=\"screen\" id=\"problems\">\n      <div class=\"shead\"><h2>Sync problems — resolution center</h2><span class=\"route\">/problems</span></div>\n      <p class=\"sdesc\">OneDrive-style error center: each row states the item, the plain-language cause, and a primary fix action.</p>\n      <div class=\"frame\" data-app-shell=\"review\" data-app-title=\"Sync problems\" data-app-kind=\"subpage\"\n        data-app-crumbs=\"Review Center|Sync problems\"\n        data-app-entry=\"Review Center status banner, failed push result, tray health row\">\n        <div class=\"tbar\"><div class=\"dots\"><i></i><i></i><i></i></div><span class=\"ttl\">Locality — Problems</span></div>\n        <div class=\"content\" style=\"padding:18px 22px\">\n          <div style=\"display:flex;align-items:center;gap:8px;font-weight:600;font-size:14px;margin-bottom:14px\">\n            <span class=\"chip c-conflict\">⚠</span> 2 items need attention</div>\n          <div class=\"card\" style=\"margin-bottom:10px;padding:12px 14px\">\n            <div style=\"display:flex;align-items:center;gap:7px;font-weight:600;font-size:12.5px\">\n              <span class=\"chip c-conflict\">⚠ Conflict</span> Auth.md <span class=\"src src-n\">N</span></div>\n            <p style=\"font-size:12px;color:var(--muted);margin:5px 0 10px\">You and Notion both edited this page.</p>\n            <div style=\"display:flex;gap:8px;align-items:center;flex-wrap:wrap\">\n              <span class=\"btn btn-primary btn-sm\" data-go=\"conflict\">Resolve…</span>\n              <span class=\"linkish\">Keep mine</span><span class=\"linkish\">Keep remote</span><span class=\"linkish\">Keep both</span></div>\n          </div>\n          <div class=\"card\" style=\"padding:12px 14px\">\n            <div style=\"display:flex;align-items:center;gap:7px;font-weight:600;font-size:12.5px\">\n              <span class=\"chip c-error\">✕ Push failed</span> Roadmap.md <span class=\"src src-n\">N</span></div>\n            <p style=\"font-size:12px;color:var(--muted);margin:5px 0 10px\">Locality no longer has permission for this workspace.</p>\n            <div style=\"display:flex;gap:8px;align-items:center\">\n              <span class=\"btn btn-primary btn-sm\" data-go=\"srcdetail\">Reconnect source</span><span class=\"linkish\">Retry</span></div>\n          </div>\n        </div>\n      </div>\n      <div class=\"notes\"><b>empty state</b> — “No problems — everything’s healthy ✓” ·\n      other rows — runtime not running → Start runtime / Open logs · unsupported name → Rename ·\n      destructive plan blocked → Review plan · “Keep both” writes name.conflict-YYYYMMDD-HHMM.md.</div>\n    </section>"
  },
  {
    id: "conflict",
    html: "    <!-- ============ 2.3.4 CONFLICT EDITOR ============ -->\n    <section class=\"screen\" id=\"conflict\">\n      <div class=\"shead\"><h2>Conflict editor — three-pane</h2><span class=\"route\">/review/:fileId</span></div>\n      <p class=\"sdesc\">Tower-style resolver: Local | editable Merged result | Remote, with click-to-take and markdown-aware auto-merge attempted first.</p>\n      <div class=\"frame\" data-app-shell=\"review\" data-app-title=\"Conflict editor\" data-app-kind=\"subpage\"\n        data-app-crumbs=\"Review Center|Conflict editor\"\n        data-app-entry=\"Review Center conflict row > Resolve, Sync problems > Resolve\">\n        <div class=\"tbar\"><div class=\"dots\"><i></i><i></i><i></i></div><span class=\"ttl\">Resolve conflict — Auth.md</span></div>\n        <div style=\"padding:14px 16px\">\n          <div style=\"display:flex;align-items:center;margin-bottom:10px\">\n            <b style=\"font-size:13px\">Resolve conflict · Auth.md</b>\n            <span class=\"btn btn-sm\" style=\"margin-left:auto\">Markdown preview</span></div>\n          <div class=\"threepane\">\n            <div class=\"pane\"><div class=\"ph2\"><span class=\"src src-n\" style=\"background:var(--teal)\">L</span>Local (agent)</div>\n              <div class=\"body\">## Overview<br><span class=\"mk\">New agent line</span><br><br>\n                <span class=\"btn btn-sm\">take all ►</span></div></div>\n            <div class=\"pane center\"><div class=\"ph2\">Merged result <span style=\"color:var(--faint);font-weight:400\">(editable)</span></div>\n              <div class=\"body\">## Overview<br><span class=\"mk\">New agent line</span> ◀──<br>\n                <span class=\"mk2\">Notion team line</span> ◀──<br>\n                <span style=\"color:var(--faint)\">(CodeMirror editor)</span></div></div>\n            <div class=\"pane\"><div class=\"ph2\"><span class=\"src src-n\">N</span>Remote (Notion)</div>\n              <div class=\"body\">## Overview<br><span class=\"mk2\">Notion team line</span><br><br>\n                <span class=\"btn btn-sm\">◄ take all</span></div></div>\n          </div>\n          <div style=\"display:flex;justify-content:flex-end;gap:8px;margin-top:12px\">\n            <span class=\"btn\" data-go=\"reviewcenter\">Cancel</span><span class=\"btn\">Mark resolved &amp; keep draft</span>\n            <span class=\"btn btn-primary\" data-go=\"pushstates\">Resolve &amp; push</span></div>\n        </div>\n      </div>\n      <div class=\"notes\"><b>merge</b> — markdown three-way auto-merge runs first; only true divergences reach this screen ·\n      word-level diff highlighting in all panes · preview toggle renders the merged markdown.</div>\n    </section>"
  },
  {
    id: "activity",
    html: "    <!-- ============ 2.4.2 ACTIVITY LOG ============ -->\n    <section class=\"screen\" id=\"activity\">\n      <div class=\"shead\"><h2>Activity</h2><span class=\"route\">/activity</span></div>\n      <p class=\"sdesc\">The History analog: an immutable, day-grouped log with expandable detail and Revert only when a safe reverse plan exists.</p>\n      <div class=\"frame\" data-app-shell=\"settings\" data-app-title=\"Activity log\" data-app-kind=\"subpage\"\n        data-app-crumbs=\"Settings|Activity log\"\n        data-app-entry=\"Settings > Activity log, Home recent activity > View all, push success > View activity\">\n        <div class=\"tbar\"><div class=\"dots\"><i></i><i></i><i></i></div><span class=\"ttl\">Locality — Activity</span></div>\n        <div class=\"setshell\">\n          <div class=\"setnav\">\n            <a href=\"#\">General</a><a href=\"#\" data-go=\"srcdetail\">Sources</a><a href=\"#\" data-go=\"settings\">Sync &amp; Live Mode</a>\n            <a class=\"on\" href=\"#\">Activity</a><a href=\"#\" data-go=\"agents\">Agents</a><a href=\"#\">Notifications</a><a href=\"#\">Network</a>\n            <a href=\"#\">Advanced</a><a href=\"#\">About</a>\n          </div>\n          <div class=\"content\" style=\"padding:18px 22px\">\n            <div class=\"sect-label\" style=\"padding-left:0\">Today</div>\n            <div class=\"card\" style=\"margin-bottom:14px\">\n              <div class=\"rowline\"><span class=\"chip c-synced\">⤴</span><span class=\"grow\">Pushed 4 changes to Notion</span>\n                <span class=\"meta\">10:24</span><span class=\"linkish\">details ▾</span></div>\n              <div class=\"rowline\"><span class=\"chip c-review\">⤵</span><span class=\"grow\">Pulled 2 pages from Notion</span>\n                <span class=\"meta\">09:03</span></div>\n              <div class=\"rowline\"><span class=\"chip c-paused\">⏸</span><span class=\"grow\">Live sync paused: conflict</span>\n                <span class=\"meta\">08:50</span><span class=\"linkish\">resolve</span></div>\n            </div>\n            <div class=\"sect-label\" style=\"padding-left:0\">Yesterday</div>\n            <div class=\"card\">\n              <div class=\"rowline\"><span class=\"chip c-synced\">⤴</span><span class=\"grow\">Pushed 1 change</span>\n                <span class=\"meta\">17:12</span></div>\n            </div>\n          </div>\n        </div>\n      </div>\n      <div class=\"notes\"><b>expanded entry</b> — affected files with per-file diff links + conditional Revert ·\n      Queue Debug is no longer a tab here; it moved to Settings → Advanced.</div>\n    </section>"
  },
  {
    id: "settings",
    html: "    <!-- ============ 2.4 SETTINGS ============ -->\n    <section class=\"screen\" id=\"settings\">\n      <div class=\"shead\"><h2>Settings — sectioned</h2><span class=\"route\">/settings/:section</span></div>\n      <p class=\"sdesc\">Left-hand sectioned nav (OneDrive pattern), deep-linkable. Shown: Sync &amp; Live Mode.</p>\n      <div class=\"frame\" data-app-shell=\"settings\" data-app-title=\"Settings\">\n        <div class=\"tbar\"><div class=\"dots\"><i></i><i></i><i></i></div><span class=\"ttl\">Locality — Settings</span></div>\n        <div class=\"setshell\">\n          <div class=\"setnav\">\n            <a href=\"#\">General</a><a href=\"#\" data-go=\"srcdetail\">Sources</a><a class=\"on\" href=\"#\">Sync &amp; Live Mode</a>\n            <a href=\"#\" data-go=\"activity\">Activity</a><a href=\"#\" data-go=\"agents\">Agents</a><a href=\"#\">Notifications</a><a href=\"#\">Network</a>\n            <a href=\"#\">Advanced</a><a href=\"#\">About</a>\n          </div>\n          <div class=\"content\" style=\"max-width:460px\">\n            <b style=\"font-size:14px\">Sync &amp; Live Mode</b>\n            <div class=\"h-min\">Default mode for new sources</div>\n            <div class=\"radio on\"><i></i><span>Review mode</span></div>\n            <div class=\"radio\"><i></i><span>Live mode</span></div>\n            <div class=\"h-min\">Live mode safety <span style=\"color:var(--faint);font-weight:400\">(always on)</span></div>\n            <div class=\"check on\"><i>✓</i><span>Pause on conflicts</span></div>\n            <div class=\"check on\"><i>✓</i><span>Pause on destructive plans</span></div>\n            <div class=\"check on\"><i>✓</i><span>Pause on review-required changes</span></div>\n            <div class=\"h-min\">Source overrides</div>\n            <div class=\"card\">\n              <div class=\"rowline\" data-go=\"srcdetail\"><span class=\"src src-n\">N</span><span class=\"grow\">Notion — Acme Team</span><span class=\"btn btn-sm\">Review mode ▾</span></div>\n              <div class=\"rowline\"><span class=\"src src-g\">G</span><span class=\"grow\" style=\"color:var(--muted)\">Google Docs</span><span class=\"chip c-draft\">Not connected</span></div>\n            </div>\n            <div style=\"margin-top:14px\"><span class=\"linkish\" data-go=\"srcdetail\">Manage per-source sync →</span></div>\n          </div>\n        </div>\n      </div>\n      <div class=\"notes\"><b>sections</b> — General (login item, theme, editor, updates) · Sources · Sync &amp; Live ·\n      Activity · Agents (detected agents + Install/Update guidance) · Notifications · Network ·\n      Advanced (logs, repair runtime, Queue Debug, danger zone) · About.</div>\n    </section>"
  },
  {
    id: "tray",
    html: "    <!-- ============ 3.1 TRAY POPOVER ============ -->\n    <section class=\"screen\" id=\"tray\">\n      <div class=\"shead\"><h2>Tray popover</h2><span class=\"route\">menu bar</span></div>\n      <p class=\"sdesc\">Dropbox/Drive anatomy: search → status → review queue → recent → controls → avatar/settings. Pause offers preset durations.</p>\n      <div class=\"tray\">\n        <div class=\"tsec\"><div class=\"wf-input\" style=\"border:0;padding:2px 0\">🔎 Locate a page or file…</div></div>\n        <div class=\"tsec\" style=\"display:flex;align-items:center;gap:8px\">\n          <span class=\"chip c-synced\">✓ All changes reviewed</span>\n          <span style=\"margin-left:auto;font-size:11px;color:var(--muted)\">Live mode</span><span class=\"toggle\"></span></div>\n        <div class=\"tsec\">\n          <div class=\"sect-label\" style=\"padding:0 0 4px\">Review Center (4)</div>\n          <div class=\"rowline\" style=\"padding:4px 0\" data-go=\"reviewcenter\"><span class=\"src src-n\">N</span><span class=\"grow\">Roadmap.md</span>\n            <span class=\"linkish\">Review</span></div>\n          <div class=\"rowline\" style=\"padding:4px 0\" data-go=\"reviewcenter\"><span class=\"src src-n\">N</span><span class=\"grow\">Auth.md</span>\n            <span class=\"linkish\">Review</span></div>\n          <div style=\"font-size:11px;padding-top:4px\"><span class=\"linkish\" data-go=\"reviewcenter\">See all →</span></div>\n        </div>\n        <div class=\"tsec\">\n          <div class=\"sect-label\" style=\"padding:0 0 4px\">Recent</div>\n          <div class=\"rowline\" style=\"padding:4px 0\" data-go=\"files\"><span class=\"src src-n\">N</span><span class=\"grow\">Standup.md</span><span class=\"meta\">3h</span></div>\n          <div class=\"rowline\" style=\"padding:4px 0\" data-go=\"files\"><span class=\"src src-n\">N</span><span class=\"grow\">Specs/Auth.md</span><span class=\"meta\">1h</span></div>\n        </div>\n        <div class=\"tsec\" style=\"display:flex;gap:12px;font-size:12px;align-items:center\">\n          <span class=\"linkish\">Pause syncing ▾</span>\n          <span style=\"margin-left:auto\" class=\"linkish\" data-go=\"files\">Open folder</span><span class=\"linkish\" data-go=\"activity\">Activity</span></div>\n        <div class=\"tsec\" style=\"display:flex;align-items:center;gap:8px;background:var(--wash)\">\n          <span class=\"avatar\"></span><span style=\"font-size:11.5px;color:var(--muted)\">user@team</span>\n          <span style=\"margin-left:auto\" class=\"linkish\" data-go=\"settings\">⚙ Settings</span><span class=\"linkish\">Quit</span></div>\n      </div>\n      <div class=\"notes\"><b>pause presets</b> — 30 min · 1 hour · Until tomorrow · Indefinitely (first three auto-resume) ·\n      left-click opens popover; all rows keyboard-navigable; Esc closes.</div>\n    </section>"
  },
  {
    id: "modals",
    html: "    <!-- ============ 3.2 DESTRUCTIVE MODALS ============ -->\n    <section class=\"screen\" id=\"modals\">\n      <div class=\"shead\"><h2>Destructive modals — app-native</h2><span class=\"route\">replaces browser confirm()</span></div>\n      <p class=\"sdesc\">One template for all destructive actions: plain-language consequences, typed confirmation for irreversible ones, red action, safe default focus.</p>\n      <div style=\"display:grid;grid-template-columns:1fr 300px;gap:20px;align-items:start\">\n        <div class=\"mcard\" role=\"dialog\" aria-label=\"Reset local state\" style=\"width:auto\">\n          <h3>Reset local state</h3>\n          <p style=\"font-size:12px;color:var(--muted)\">This removes Locality’s local database, credentials, and sync metadata on this machine.</p>\n          <ul style=\"font-size:12px;color:var(--muted);margin:10px 0 0 16px;line-height:1.8\">\n            <li>Your files in the mounted folder are kept.</li>\n            <li>Your Notion workspace is not changed.</li>\n            <li>You will need to reconnect and re-verify the mount.</li>\n          </ul>\n          <div style=\"margin-top:12px;font-size:12px\">Type <b style=\"font-family:var(--mono)\">RESET</b> to confirm:</div>\n          <div class=\"wf-input\" style=\"max-width:180px;margin-top:6px\">________</div>\n          <div class=\"mfoot\"><span class=\"btn\">Cancel</span>\n            <span class=\"btn btn-danger\" disabled aria-disabled=\"true\">Reset local state</span></div>\n        </div>\n        <div class=\"mcard\" role=\"dialog\" aria-label=\"Pause syncing\" style=\"width:auto\">\n          <h3>Pause syncing</h3>\n          <div class=\"radio\"><i></i><span>30 minutes</span></div>\n          <div class=\"radio\"><i></i><span>1 hour</span></div>\n          <div class=\"radio\"><i></i><span>Until tomorrow</span></div>\n          <div class=\"radio\"><i></i><span>Indefinitely</span></div>\n          <div class=\"mfoot\"><span class=\"btn\">Cancel</span><span class=\"btn btn-primary\">Pause</span></div>\n        </div>\n      </div>\n      <div class=\"notes\"><b>rules</b> — focus lands on Cancel · Esc = Cancel · red button disabled until typed confirmation ·\n      same template covers Prepare for uninstall and page-deletion gates.</div>\n    </section>"
  },
  {
    id: "legend",
    html: "    <!-- ============ 4.2 STATUS LEGEND ============ -->\n    <section class=\"screen\" id=\"legend\">\n      <div class=\"shead\"><h2>Status chip legend</h2><span class=\"route\">used on every list row</span></div>\n      <p class=\"sdesc\">One vocabulary everywhere: sidebar badges, file rows, tray, and OS file badges all map to these seven states. Never color alone — always icon + text.</p>\n      <div class=\"frame\"><div style=\"padding:22px 26px\">\n        <div class=\"card\">\n          <div class=\"rowline\"><span class=\"chip c-synced\">✓ Synced</span><span class=\"grow\" style=\"color:var(--muted)\">local matches remote</span><span class=\"meta\">teal #087b72</span></div>\n          <div class=\"rowline\"><span class=\"chip c-review-needed\">● Needs review</span><span class=\"grow\" style=\"color:var(--muted)\">local edits awaiting approval</span><span class=\"meta\">amber #C08A00</span></div>\n          <div class=\"rowline\"><span class=\"chip c-draft\">◐ Draft</span><span class=\"grow\" style=\"color:var(--muted)\">intentionally not pushed</span><span class=\"meta\">slate #64748b</span></div>\n          <div class=\"rowline\"><span class=\"chip c-review\">⟳ Reviewing</span><span class=\"grow\" style=\"color:var(--muted)\">in the push plan / being pushed</span><span class=\"meta\">blue #2563eb</span></div>\n          <div class=\"rowline\"><span class=\"chip c-conflict\">⚠ Conflict</span><span class=\"grow\" style=\"color:var(--muted)\">local &amp; remote diverged</span><span class=\"meta\">orange #d97706</span></div>\n          <div class=\"rowline\"><span class=\"chip c-paused\">⏸ Paused</span><span class=\"grow\" style=\"color:var(--muted)\">sync paused (user or Live-mode)</span><span class=\"meta\">slate #64748b</span></div>\n          <div class=\"rowline\"><span class=\"chip c-error\">✕ Error</span><span class=\"grow\" style=\"color:var(--muted)\">push / pull / runtime failure</span><span class=\"meta\">red #dc2626</span></div>\n        </div>\n        <div class=\"legend\">\n          <span class=\"src src-n\">N</span><span style=\"font-size:11.5px;color:var(--muted)\">Notion source badge</span>\n          <span class=\"src src-g\" style=\"margin-left:14px\">G</span><span style=\"font-size:11.5px;color:var(--muted)\">Google Docs source badge</span>\n        </div>\n      </div></div>\n      <div class=\"notes\"><b>surfacing</b> — sidebar: numeric badge on Review Center, Problems appear only when attention is required · file rows: chip per row ·\n      tray: aggregate line + per-item · OS badges: synced ✓ / in-flight progress / error ! mapped per platform.</div>\n    </section>"
  },
  {
    id: "srcdetail",
    html: "    <!-- ============ 2.2.1 SOURCE DETAIL ============ -->\n    <section class=\"screen\" id=\"srcdetail\">\n      <div class=\"shead\"><h2>Source detail</h2><span class=\"route\">/sources/:id</span></div>\n      <p class=\"sdesc\">Everything about one connected workspace: access, local files, mount health, and the danger zone — without crowding Home or Sources.</p>\n      <div class=\"frame\" data-app-shell=\"sources\" data-app-title=\"Source detail\" data-app-kind=\"subpage\"\n        data-app-crumbs=\"Sources|Notion - Acme Team\"\n        data-app-entry=\"Sources card > Details, Home source health card, connector warning > Manage source\">\n        <div class=\"tbar\"><div class=\"dots\"><i></i><i></i><i></i></div><span class=\"ttl\">Locality — Notion · Acme Team</span></div>\n        <div class=\"content\" style=\"padding:16px 22px\">\n          <div style=\"font-size:12px;margin-bottom:8px\"><span class=\"linkish\" data-go=\"sources\">← Sources</span></div>\n          <div style=\"display:flex;align-items:center;gap:8px;font-weight:600;font-size:14px\">\n            <span class=\"src src-n\">N</span>Notion — Acme Team\n            <span class=\"chip c-synced\" style=\"margin-left:auto\">✓ Healthy</span></div>\n          <div class=\"pathchip\" style=\"margin:10px 0\"><span>~/Library/CloudStorage/Locality/notion</span><em>Copy</em></div>\n          <div style=\"display:flex;gap:8px;flex-wrap:wrap;margin-bottom:14px\">\n            <span class=\"btn btn-sm\" data-go=\"files\">Open folder</span><span class=\"btn btn-sm\" data-go=\"files\">Open in VS Code</span>\n            <span class=\"btn btn-sm\">Change access</span><span class=\"btn btn-sm\">Pull changes ⤵</span></div>\n          <div style=\"display:grid;grid-template-columns:1fr 1fr;gap:10px\">\n            <div class=\"card\"><div class=\"card-h\">Access</div>\n              <div class=\"rowline\"><span class=\"grow\" style=\"color:var(--muted)\">Workspace</span>Acme Team</div>\n              <div class=\"rowline\"><span class=\"grow\" style=\"color:var(--muted)\">Account</span>u@acme.com</div>\n              <div class=\"rowline\"><span class=\"grow\" style=\"color:var(--muted)\">Scope</span>14 top pages</div>\n              <div class=\"rowline\"><span class=\"grow\" style=\"color:var(--muted)\">Permission</span>Read + write</div>\n              <div class=\"rowline\"><span class=\"linkish\">Open in Notion ↗</span></div></div>\n            <div class=\"card\"><div class=\"card-h\">Local files</div>\n              <div class=\"rowline\"><span class=\"grow\" style=\"color:var(--muted)\">Projection</span>File Provider</div>\n              <div class=\"rowline\"><span class=\"grow\" style=\"color:var(--muted)\">Pages</span>412</div>\n              <div class=\"rowline\"><span class=\"grow\" style=\"color:var(--muted)\">Databases</span>3</div>\n              <div class=\"rowline\"><span class=\"grow\" style=\"color:var(--muted)\">Root</span>exists <span class=\"chip c-synced\">✓</span></div>\n              <div class=\"rowline\"><span class=\"grow\" style=\"color:var(--muted)\">Root sync</span><span class=\"chip c-synced\">Enabled</span></div></div>\n          </div>\n          <div class=\"card\" style=\"margin-top:10px\">\n            <div class=\"card-h\">Sync for this source</div>\n            <div class=\"rowline\"><span class=\"grow\" style=\"color:var(--muted)\">Mode</span><span class=\"btn btn-sm\">Review mode ▾</span></div>\n            <div class=\"rowline\"><span class=\"grow\" style=\"color:var(--muted)\">Clean remote pulls</span><span class=\"chip c-synced\">On</span></div>\n            <div class=\"rowline\"><span class=\"grow\" style=\"color:var(--muted)\">Live safe pushes</span><span class=\"chip c-paused\">Off</span><span class=\"btn btn-sm\">Turn on</span></div>\n            <div class=\"rowline\"><span class=\"grow\" style=\"color:var(--muted)\">Review rules</span>Destructive, conflict, large plan</div>\n            <div class=\"rowline\"><span class=\"btn btn-sm\">Sync now</span><span class=\"btn btn-sm\">Pause source ▾</span><span class=\"linkish\">Use global default</span></div>\n          </div>\n          <div class=\"h-min\">Mount health</div>\n          <div style=\"display:flex;gap:14px;flex-wrap:wrap;font-size:12px\">\n            <span><span class=\"chip c-synced\">✓</span> Runtime running</span>\n            <span><span class=\"chip c-synced\">✓</span> Provider registered</span>\n            <span><span class=\"chip c-synced\">✓</span> Credentials valid</span>\n            <span><span class=\"chip c-synced\">✓</span> Last sync 2m ago</span></div>\n          <details class=\"danger-accordion\">\n            <summary>⚠ Danger zone <span style=\"color:var(--muted);font-weight:500\">Closed by default</span></summary>\n            <div class=\"danger-body\">\n              <span class=\"btn btn-sm\" style=\"border-color:var(--red);color:var(--red)\">Reset local state</span>\n              <span class=\"btn btn-sm\" style=\"border-color:var(--red);color:var(--red)\">Disconnect source</span>\n              <span style=\"font-size:11px;color:var(--muted)\">Both open typed-confirmation modals.</span></div>\n          </details>\n        </div>\n      </div>\n      <div class=\"notes\"><b>notes</b> — a failed health check swaps to ✕ Error with a fix action (Start runtime / Reconnect / Open logs) ·\n      per-source sync controls override the global default; Danger Zone stays collapsed until explicitly opened.</div>\n    </section>"
  },
  {
    id: "locate",
    html: "    <!-- ============ 2.1.2 LOCATE RESULTS ============ -->\n    <section class=\"screen\" id=\"locate\">\n      <div class=\"shead\"><h2>Locate — results open</h2><span class=\"route\">/locate?q=…</span></div>\n      <p class=\"sdesc\">Type a title → ranked suggestions with source badges and status. Paste a URL → resolves straight to the Located result.</p>\n      <div class=\"frame\" data-app-shell=\"home\" data-app-title=\"Locate results\" data-app-kind=\"subpage\"\n        data-app-crumbs=\"Home|Locate results\"\n        data-app-entry=\"Home locate field, tray search, keyboard shortcut /\">\n        <div class=\"tbar\"><div class=\"dots\"><i></i><i></i><i></i></div><span class=\"ttl\">Locality — Home</span></div>\n        <div class=\"content\" style=\"padding:20px 24px;max-width:560px\">\n          <div class=\"h-min\" style=\"margin-top:0\">Locate a page</div>\n          <div class=\"wf-input\" style=\"color:var(--ink)\">🔎 auth<span style=\"margin-left:2px;border-left:1px solid var(--ink)\"></span></div>\n          <div class=\"card\" style=\"margin-top:-1px;border-top-left-radius:0;border-top-right-radius:0\">\n            <div class=\"rowline\" style=\"background:var(--teal-wash)\" data-go=\"files\"><span class=\"grow\">📄 Auth.md</span>\n              <span class=\"src src-n\">N</span><span class=\"chip c-synced\">✓ Synced</span><span class=\"meta\">Specs/</span></div>\n            <div class=\"rowline\" data-go=\"reviewcenter\"><span class=\"grow\">📄 Auth-review.md</span>\n              <span class=\"src src-n\">N</span><span class=\"chip c-review-needed\">● Needs review</span><span class=\"meta\">Drafts/</span></div>\n            <div class=\"rowline\"><span class=\"grow\">📄 OAuth broker notes</span>\n              <span class=\"src src-n\">N</span><span class=\"chip c-synced\">✓ Synced</span><span class=\"meta\">Eng/Infra/</span></div>\n            <div class=\"rowline\" style=\"justify-content:center;color:var(--faint);font-size:11px\">No more matches in current access</div>\n          </div>\n          <div class=\"h-min\">Located <span class=\"chip c-synced\">✓</span></div>\n          <div class=\"pathchip\"><span>~/Library/CloudStorage/Locality/notion/Specs/Auth.md</span></div>\n          <div style=\"display:flex;gap:8px;margin-top:10px\">\n            <span class=\"btn btn-sm btn-primary\">Copy path</span>\n            <span class=\"btn btn-sm\" data-go=\"files\">Reveal in Finder</span><span class=\"btn btn-sm\" data-go=\"files\">Open in editor</span></div>\n        </div>\n      </div>\n      <div class=\"notes\"><b>URL paste</b> — skips suggestions, resolves directly · <b>not granted</b> — inline error:\n      “That page isn’t shared with Locality. [Change Notion access]” · suggestions require ≥2 characters, debounced.</div>\n    </section>"
  },
  {
    id: "pushstates",
    html: "    <!-- ============ 2.3.2 PUSH STATES ============ -->\n    <section class=\"screen\" id=\"pushstates\">\n      <div class=\"shead\"><h2>Push approval — progress and success</h2><span class=\"route\">/review/push</span></div>\n      <p class=\"sdesc\">Progress is per-file and honest; success names exactly what happened and points to Activity for audit and rare safe reversions.</p>\n      <div style=\"display:grid;grid-template-columns:1fr 1fr;gap:20px;align-items:start\">\n        <div class=\"mcard\" role=\"dialog\" aria-label=\"Pushing\" style=\"width:auto\">\n          <h3><span class=\"chip c-review\">⟳</span> Pushing 2 of 3…</h3>\n          <div style=\"height:8px;border-radius:99px;background:var(--line-soft);margin:10px 0;overflow:hidden\">\n            <div style=\"width:66%;height:100%;background:var(--teal)\"></div></div>\n          <div class=\"rowline\" style=\"padding:5px 0\"><span class=\"chip c-synced\">✓</span><span class=\"grow\">Roadmap.md pushed</span></div>\n          <div class=\"rowline\" style=\"padding:5px 0\"><span class=\"chip c-review\">⟳</span><span class=\"grow\">Auth.md pushing…</span></div>\n          <div class=\"rowline\" style=\"padding:5px 0;border-bottom:0\"><span class=\"chip c-paused\">○</span><span class=\"grow\">Old.md queued</span></div>\n          <div class=\"mfoot\"><span class=\"btn\" data-go=\"reviewcenter\">Cancel remaining</span></div>\n        </div>\n        <div class=\"mcard\" role=\"dialog\" aria-label=\"Pushed\" style=\"width:auto\">\n          <h3><span class=\"chip c-synced\">✓</span> Pushed 3 changes to Notion</h3>\n          <p style=\"font-size:12px;color:var(--muted);margin-top:4px\">2 pages updated · 1 row updated · 1 page deleted</p>\n          <div class=\"mfoot\" style=\"justify-content:space-between;align-items:center\">\n            <span class=\"linkish\" data-go=\"activity\">View reverse plan</span>\n            <span style=\"display:flex;gap:8px\"><span class=\"btn\" data-go=\"activity\">View activity</span>\n            <span class=\"btn btn-primary\" data-go=\"reviewcenter\">Done</span></span></div>\n        </div>\n      </div>\n      <div class=\"notes\"><b>partial failure</b> — success card lists failed items with “→ View in Sync Problems”; nothing\n      silently retries · Cancel remaining never rolls back already-pushed files; Activity shows a Revert option only when safe.</div>\n    </section>"
  },
  {
    id: "agents",
    html: "    <!-- ============ 2.4.1 SETTINGS AGENTS ============ -->\n    <section class=\"screen\" id=\"agents\">\n      <div class=\"shead\"><h2>Settings · Agents</h2><span class=\"route\">/settings/agents</span></div>\n      <p class=\"sdesc\">Per-agent guidance status with one install/update action; the MCP fallback is surfaced as a configured capability, not jargon.</p>\n      <div class=\"frame\" data-app-shell=\"settings\" data-app-title=\"Settings · Agents\" data-app-kind=\"subpage\"\n        data-app-crumbs=\"Settings|Agents\"\n        data-app-entry=\"Settings sidebar > Agents, onboarding ready > Install guidance, Review Center row > Rule\">\n        <div class=\"tbar\"><div class=\"dots\"><i></i><i></i><i></i></div><span class=\"ttl\">Locality — Settings</span></div>\n        <div class=\"setshell\">\n          <div class=\"setnav\">\n            <a href=\"#\">General</a><a href=\"#\">Sources</a><a href=\"#\">Sync &amp; Live Mode</a>\n            <a href=\"#\" data-go=\"activity\">Activity</a><a class=\"on\" href=\"#\">Agents</a><a href=\"#\">Notifications</a><a href=\"#\">Network</a>\n            <a href=\"#\">Advanced</a><a href=\"#\">About</a>\n          </div>\n          <div class=\"content\" style=\"max-width:460px\">\n            <b style=\"font-size:14px\">Agents</b>\n            <p style=\"font-size:12px;color:var(--muted);margin:4px 0 12px\">\n              Locality writes guidance files so local agents know the filesystem contract.</p>\n            <div class=\"h-min\">Detected on this machine</div>\n            <div class=\"card\">\n              <div class=\"rowline\">⚡<span class=\"grow\">Claude Code</span><span class=\"chip c-synced\">✓ Guidance installed</span></div>\n              <div class=\"rowline\">⚡<span class=\"grow\">Cursor</span><span class=\"chip c-synced\">✓ Guidance installed</span></div>\n              <div class=\"rowline\">⚡<span class=\"grow\">Warp</span><span class=\"chip c-review-needed\">● Update available</span></div>\n              <div class=\"rowline\">⚡<span class=\"grow\">Gemini CLI</span><span class=\"chip c-draft\">○ Not installed</span></div>\n            </div>\n            <div style=\"display:flex;gap:10px;align-items:center;margin-top:12px\">\n              <span class=\"btn btn-primary btn-sm\" data-go=\"agents\">Install / Update guidance</span>\n              <span class=\"linkish\">View written files →</span></div>\n            <div class=\"rowline\" style=\"margin-top:14px;border:1px solid var(--line-soft);border-radius:6px\">\n              <span class=\"grow\" style=\"color:var(--muted)\">MCP fallback: <b style=\"font-family:var(--mono);color:var(--ink)\">loc</b> server</span>\n              <span class=\"chip c-synced\">✓ Configured</span></div>\n          </div>\n        </div>\n      </div>\n      <div class=\"notes\"><b>after install</b> — each row updates in place with a per-agent result; failures show ✕ Error\n      with “Open file location” · never edits opaque app databases — file-backed config only.</div>\n    </section>"
  },
  {
    id: "empties",
    html: "    <!-- ============ 4.1 EMPTY AND LOADING STATES ============ -->\n    <section class=\"screen\" id=\"empties\">\n      <div class=\"shead\"><h2>Empty &amp; loading states</h2><span class=\"route\">sheet</span></div>\n      <p class=\"sdesc\">Every empty state is an invitation to act — a verb and a button, never mood copy. Lists load with skeletons; spinners are reserved for whole-screen waits.</p>\n      <div style=\"display:grid;grid-template-columns:1fr 1fr;gap:16px\">\n        <div class=\"card\" style=\"padding:26px;text-align:center\">\n          <div class=\"aperture\" style=\"width:26px;height:26px;border-width:3px;margin:0 auto 10px\"></div>\n          <div style=\"font-weight:600;font-size:12.5px\">Connect your first source to get started.</div>\n          <div style=\"margin-top:10px\"><span class=\"btn btn-primary btn-sm\">Connect Notion</span></div>\n          <div class=\"meta\" style=\"margin-top:10px;font-size:10.5px;color:var(--faint)\">Home — no sources</div>\n        </div>\n        <div class=\"card\" style=\"padding:26px;text-align:center\">\n          <div style=\"font-size:20px;color:var(--teal);margin-bottom:8px\">✓</div>\n          <div style=\"font-weight:600;font-size:12.5px\">No changes waiting for review.</div>\n          <div style=\"font-size:11.5px;color:var(--muted)\">Agent edits will appear in Review Center.</div>\n          <div class=\"meta\" style=\"margin-top:10px;font-size:10.5px;color:var(--faint)\">Review Center — empty</div>\n        </div>\n        <div class=\"card\" style=\"padding:26px;text-align:center\">\n          <div style=\"font-size:20px;color:var(--teal);margin-bottom:8px\">✓</div>\n          <div style=\"font-weight:600;font-size:12.5px\">No problems — everything’s healthy.</div>\n          <div class=\"meta\" style=\"margin-top:10px;font-size:10.5px;color:var(--faint)\">Problems — empty</div>\n        </div>\n        <div class=\"card\" style=\"padding:16px\">\n          <div style=\"display:grid;gap:9px\">\n            <div style=\"height:11px;border-radius:4px;background:linear-gradient(90deg,var(--line-soft) 60%,transparent 60%)\"></div>\n            <div style=\"height:11px;border-radius:4px;background:linear-gradient(90deg,var(--line-soft) 45%,transparent 45%)\"></div>\n            <div style=\"height:11px;border-radius:4px;background:linear-gradient(90deg,var(--line-soft) 52%,transparent 52%)\"></div>\n            <div style=\"height:11px;border-radius:4px;background:linear-gradient(90deg,var(--line-soft) 38%,transparent 38%)\"></div>\n          </div>\n          <div style=\"font-size:11px;color:var(--muted);margin-top:12px\">Skeleton rows — no spinner for waits &lt;400ms</div>\n          <div class=\"meta\" style=\"margin-top:6px;font-size:10.5px;color:var(--faint)\">Files — loading</div>\n        </div>\n      </div>\n      <div class=\"notes\"><b>error copy rule</b> — always name the cause and the fix in the interface’s voice; errors\n      never apologize and are never vague about what happened.</div>\n    </section>"
  }
]);
